            self.bias_hh_0 = torch.nn.Parameter(ref_rnn.bias_hh_l0.clone())
            self.bias_ih_1 = torch.nn.Parameter(ref_rnn.bias_ih_l1.clone())
            self.bias_hh_1 = torch.nn.Parameter(ref_rnn.bias_hh_l1.clone())
